arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Preserve "Discriminator" property name for existing documents (default changed to "$type" in EF Core 9)
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve discriminator-prefixed id format ("Blog|1") for existing documents (EF Core 9 uses key-only ids)
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // HasIndex removed — Cosmos DB indexing is managed via the container's indexing policy, not EF Core.
    // In EF Core 9, HasIndex on Cosmos entities throws InvalidOperationException at startup.
}

